	if err != nil {
		panic(err)
	}

	doc := finalDoc{Rows: rows, Summary: map[string]any{"total": len(raw.Raw), "agree": (nowAgree && priorAgree)}}
	out, err := json.MarshalIndent(doc, "", "  ")
	if err != nil {
		panic(err)
	}
	if err := os.WriteFile(os.Args[2], append(out, '\n'), 0o644); err != nil {
		panic(err)
	}
}
