package main

import (
	"encoding/json"
	"errors"
	"os"
	"reflect"
)

type entry struct {
	Case      string `json:"case"`
	Produced  []int  `json:"produced"`
	Trace     []int  `json:"slot_trace"`
	OrderUsed []int  `json:"order_used"`
	Packed    bool   `json:"packed"`
	Grouped   bool   `json:"grouped"`
	Reuse     bool   `json:"reuse"`
}

type rawDoc struct {
	Raw []entry `json:"raw"`
}

type finalDoc struct {
	Rows    []entry        `json:"rows"`
	Summary map[string]any `json:"summary"`
}

func indexByCase(rows []entry) (map[string]entry, error) {
	m := make(map[string]entry, len(rows))
	for _, r := range rows {
		if r.Case == "" {
			return nil, errors.New("row missing case")
		}
		if _, exists := m[r.Case]; exists {
			return nil, errors.New("duplicate case: " + r.Case)
		}
		m[r.Case] = r
	}
	return m, nil
}

func eqSix(a, b entry) bool {
	if a.Case != b.Case {
		return false
	}
	if !reflect.DeepEqual(a.Produced, b.Produced) {
		return false
	}
	if !reflect.DeepEqual(a.Trace, b.Trace) {
		return false
	}
	if !reflect.DeepEqual(a.OrderUsed, b.OrderUsed) {
		return false
	}
	if a.Packed != b.Packed || a.Grouped != b.Grouped || a.Reuse != b.Reuse {
		return false
	}
	return true
}

// agree is true iff every case in raw has a corresponding report row matching
// on produced, slot_trace, order_used, packed, grouped, reuse.
func agreeRawVsRows(raw []entry, rows []entry) (bool, error) {
	rawBy, err := indexByCase(raw)
	if err != nil {
		return false, err
	}
	rowsBy, err := indexByCase(rows)
	if err != nil {
		return false, err
	}
	if len(rawBy) != len(rowsBy) {
		return false, nil
	}
	for k, rr := range rawBy {
		fr, ok := rowsBy[k]
		if !ok {
			return false, nil
		}
		if !eqSix(rr, fr) {
			return false, nil
		}
	}
	return true, nil
}

func main() {
	if len(os.Args) != 3 {
		panic("usage: align raw final")
	}
	buf, err := os.ReadFile(os.Args[1])
	if err != nil {
		panic(err)
	}
	var raw rawDoc
	if err := json.Unmarshal(buf, &raw); err != nil {
		panic(err)
